var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"어머, 무슨 그런 말씀을.","JPN":"まあ、なんてもったいないお言葉。","ENG":"Oh my, you’re making me blush.","TWN":"哎呀，這麼客氣。"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님. 과찬이세요. 그 정도야 제겐 일도 아니니까요.","JPN":"ヘイブン様、褒めすぎです。このくらい、私にはどうってこともないのですから。","ENG":"Mr. Haven, you’re too kind. It was no trouble on my part.","TWN":"天堂先生過獎，那點小事對我而言不算什麼。"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래요? 그럼 당신이 이룩한 <color=#ffd34c>헤이븐 랜드</color>……","JPN":"そうですか？　それでは、あなたが築いてきた<color=#ffd34c>ヘイブンランド</color>……","ENG":"Is that so? Then <color=#ffd34c>Havenland</color> and what you’ve accomplished...","TWN":"是嗎？那您建立的<color=#ffd34c>天堂樂園</color>……"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아니, 당신의 이름을 팔아 제가 직접 쌓아 올린 나의 <color=#ffd34c>헤이븐 랜드</color>를……","JPN":"いいえ、あなたの名をかたって私が直接築いてきた私の<color=#ffd34c>ヘイブンランド</color>を……","ENG":"No, \\"my\\" <color=#ffd34c>Havenland</color> that \\"I\\" founded using your name...","TWN":"不對，您只是掛名而已，<color=#ffd34c>天堂樂園</color>是我親手建立起來的……"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이렇게.","JPN":"こうやって。","ENG":"How...!","TWN":"像這樣…"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이렇게.","JPN":"こうやって。","ENG":"Could...!","TWN":"這樣…"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이렇……","JPN":"こう……","ENG":"Y-!","TWN":"這……"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이게…… 이게 지금…….","JPN":"これ……これはいったい……","ENG":"What... have I...?","TWN":"我……我現在……"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"내가 무슨 짓을…….","JPN":"私、なんてことを……","ENG":"What have I done...?!","TWN":"這是在做什麼……"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"꺄하하하! 이게 헤이븐 님께서 말한 그 재미인가요? 그런가요?!","JPN":"キャハハハ！　これがヘイブン様がおっしゃった楽しさなのですか？　そうなんですか！？","ENG":"Kyahahaha! Is this the \\"entertainment\\" Mr. Haven mentioned? Is it?!","TWN":"哈哈哈哈！這就是天堂先生說的興趣嗎？是嗎？！"},"stage":{"bg":"DREAM_03","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"난… 그렇게 웃지 않아. 이건 내가 아니야. 내가 그런 게 아니야……!","JPN":"私は……そんな風に笑わないわ。これは私じゃない。私がやったんじゃない……！","ENG":"No... I don't laugh like that. This isn't me. I didn't do anything...!","TWN":"我…我沒有笑，那不是我，我沒有……！"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"……다 없어졌네.","JPN":"……全部消えたわね。","ENG":"It's... all over.","TWN":"我現在變得一無所有……"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"하늘 위에서… 땅바닥 아래로 쿵… 처박혀 버렸어.","JPN":"空の上から……地面の下にドンと……めり込んでしまった。","ENG":"It fell... from the sky... and crashed.","TWN":"從天堂…落入凡間…"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"휴. 어쩔 수 없지.","JPN":"はあ。仕方ないわね。","ENG":"*Sigh* Oh well.","TWN":"哀，沒辦法。"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"가방도 팔고… 모자도 팔고… 구두도 팔고… 옷도 팔고… 또 뭘 팔지?","JPN":"かばんも売って……帽子も売って……靴も……服も売って……他に何を売る？","ENG":"I guess I'll just have to sell my bags, hats, boots, clothes, and... What else can I sell?","TWN":"只好賣包包…賣帽子…賣鞋子…賣衣服…還有什麼可以賣？"},"stage":{"bg":"DREAM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};